SELECT DISTINCT T1.user_name
FROM users AS T1
JOIN commit_history AS T2 ON T1.user_id = T2.user_id;

SELECT commit_message, author 
FROM commit_history 
WHERE commit_id = 1;

SELECT user_name
FROM users
WHERE user_id IN (SELECT user_id FROM commit_history);

SELECT DISTINCT d.triggered_by
FROM deployments d
WHERE d.triggered_by NOT IN (
    SELECT DISTINCT b.triggered_by
    FROM builds b
);

SELECT COUNT(deployment_id) AS production_environment_deployments
FROM deployments
WHERE environment = 'Production';

SELECT log_message
FROM build_logs
WHERE build_id = 1;

SELECT deployment_id, log_message
FROM deployment_logs
WHERE log_message = 'Deployment started';
